//! gRPC message types + service traits for nine-snake v0.3.
//!
//! In a build-environment with `cargo` available these types would be
//! generated by `tonic_build::compile_protos` from
//! `proto/nine_snake.proto`. Because the v0.3 hand-off happens in an
//! environment without `cargo`, the generation step is **simulated**
//! by this file: every proto message is mirrored as a plain Rust
//! struct that round-trips through a JSON body wrapped in a single
//! `prost` field.
//!
//! v0.5 will replace this hand-rolled module with the real generated
//! code; the *public* API (struct names, field names, service
//! methods) is identical so the migration is mechanical.

use serde::{Deserialize, Serialize};

/// One byte string is exactly what tonic transports under the hood.
/// We keep this newtype so the call-sites read like the real
/// `prost::Message` API.
pub type Bytes = Vec<u8>;

// ---------------------------------------------------------------------------
// Enums
// ---------------------------------------------------------------------------

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "SCREAMING_SNAKE_CASE")]
#[derive(Default)]
pub enum MemoryLayer {
    #[default]
    Unspecified = 0,
    L0 = 1,
    L1 = 2,
    L2 = 3,
    L3 = 4,
    L4 = 5,
    L5 = 6,
    L6 = 7,
    L7 = 8,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "SCREAMING_SNAKE_CASE")]
#[derive(Default)]
pub enum MemoryType {
    #[default]
    Unspecified = 0,
    Semantic = 1,
    Episodic = 2,
    Procedural = 3,
    Emotional = 4,
    Metacognitive = 5,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "SCREAMING_SNAKE_CASE")]
#[derive(Default)]
pub enum AgentKind {
    #[default]
    Unspecified = 0,
    Coder = 1,
    Writer = 2,
    Reviewer = 3,
}

