// ---------------------------------------------------------------------------
// Wire codec
// ---------------------------------------------------------------------------
//
// The real tonic-generated code would derive `prost::Message` on
// every type above and call `encode_length_delimited` /
// `decode_length_delimited` on the wire. We use a tiny JSON
// indirection that maps each message to a single-length-prefixed
// JSON blob, which keeps the server stub honest about its
// `tonic::Request<Bytes>` boundary and lets the v0.5 generated code
// slot in cleanly.

/// JSON wrapper used as the on-wire body for every gRPC method.
#[derive(Debug, Clone, Serialize, serde::Deserialize)]
pub struct JsonBody<T>(pub T);

impl<T> JsonBody<T>
where
    T: Serialize,
{
    pub fn encode(&self) -> Result<Bytes, serde_json::Error> {
        serde_json::to_vec(&self.0)
    }
}

impl<T> JsonBody<T>
where
    T: for<'de> Deserialize<'de>,
{
    pub fn decode(bytes: &[u8]) -> Result<Self, serde_json::Error> {
        serde_json::from_slice(bytes).map(JsonBody)
    }
}
